        // ── Route-logic unit tests (pure Rust, no Metal device needed) ────────

        #[test]
        fn test_choose_gpu_topk_route_all_cases() {
            // k=0 → always CPU
            assert_eq!(
                choose_gpu_topk_route(0, true, true),
                GpuTopkRoute::CpuFallback,
                "k=0"
            );
            // compact_env=false → always CPU
            assert_eq!(
                choose_gpu_topk_route(1, false, false),
                GpuTopkRoute::CpuFallback,
                "k=1, compact_env=false"
            );
            assert_eq!(
                choose_gpu_topk_route(50, false, true),
                GpuTopkRoute::CpuFallback,
                "k=50, compact_env=false"
            );
            // k=1, compact_env=true → CpuFallback (GPU 2.70× slower than CPU NEON after R1)
            assert_eq!(
                choose_gpu_topk_route(1, true, false),
                GpuTopkRoute::CpuFallback,
                "k=1, compact_env=true, no select"
            );
            assert_eq!(
                choose_gpu_topk_route(1, true, true),
                GpuTopkRoute::CpuFallback,
                "k=1, compact_env=true, select"
            );
            // k=2..=64, compact_env=true, no selection_env → CpuFallback
            for k in [2usize, 10, 50, 64] {
                assert_eq!(
                    choose_gpu_topk_route(k, true, false),
                    GpuTopkRoute::CpuFallback,
                    "k={k}, no LATTICE_COMPACT_TOPK_SELECT"
                );
            }
            // k=50 with both env flags → HierarchicalK50 (R2 experimental).
            assert_eq!(
                choose_gpu_topk_route(50, true, true),
                GpuTopkRoute::HierarchicalK50,
                "k=50 with both env flags must use HierarchicalK50"
            );
            // Other k>1 values must not enter any GPU route.
            for k in [2usize, 10, 49, 51, 64, 65, 128, 256] {
                assert_eq!(
                    choose_gpu_topk_route(k, true, true),
                    GpuTopkRoute::CpuFallback,
                    "k={k} must not enter any GPU top-k route"
                );
            }
            // k>256 → always CpuFallback
            assert_eq!(
                choose_gpu_topk_route(257, true, true),
                GpuTopkRoute::CpuFallback,
                "k=257"
            );
            assert_eq!(
                choose_gpu_topk_route(1000, true, true),
                GpuTopkRoute::CpuFallback,
                "k=1000"
            );
        }

        // ── GPU-CPU argmax parity tests (requires Metal device) ──────────────

        #[test]
        fn test_gpu_argmax_parity_k1() {
            let Some(device) = Device::system_default() else {
                return;
            };
            let queue = device.new_command_queue();
            let opts = CompileOptions::new();
            let library = device
                .new_library_with_source(MSL_SOURCE, &opts)
                .expect("MSL compile");
            let first_fn = library
                .get_function("logits_argmax_first", None)
                .expect("logits_argmax_first");
            let merge_fn = library
                .get_function("logits_argmax_merge", None)
                .expect("logits_argmax_merge");
            let first_pipe = device
                .new_compute_pipeline_state_with_function(&first_fn)
                .expect("argmax_first pipeline");
            let merge_pipe = device
                .new_compute_pipeline_state_with_function(&merge_fn)
                .expect("argmax_merge pipeline");

            // Dispatch GPU argmax and return the winning token_id.
            let gpu_argmax = |logits: &[f32]| -> u32 {
                let vocab_size = logits.len() as u32;
                let groups = vocab_size.div_ceil(1024);
                let in_buf = make_buffer(&device, logits, "logits");
                // scratch_a: groups × TopKCandidate (8 bytes = float logit + uint token_id)
                let scratch_a_zeros: Vec<f32> = vec![0.0; (groups as usize) * 2];
                let scratch_a = make_buffer(&device, &scratch_a_zeros, "scratch_a");
                // scratch_b: 1 TopKCandidate
                let scratch_b = make_buffer(&device, &[0.0f32; 2], "scratch_b");

                let cmd = queue.new_command_buffer();
                {
                    let enc = cmd.new_compute_command_encoder();
                    enc.set_compute_pipeline_state(&first_pipe);
                    enc.set_buffer(0, Some(&in_buf), 0);
                    enc.set_buffer(1, Some(&scratch_a), 0);
                    enc.set_bytes(2, 4, &vocab_size as *const u32 as *const _);
                    enc.dispatch_thread_groups(
                        MTLSize::new(groups as u64, 1, 1),
                        MTLSize::new(1024, 1, 1),
                    );
                    enc.set_compute_pipeline_state(&merge_pipe);
                    enc.set_buffer(0, Some(&scratch_a), 0);
                    enc.set_buffer(1, Some(&scratch_b), 0);
                    enc.set_bytes(2, 4, &groups as *const u32 as *const _);
                    enc.dispatch_thread_groups(MTLSize::new(1, 1, 1), MTLSize::new(1024, 1, 1));
                    enc.end_encoding();
                }
                cmd.commit();
                cmd.wait_until_completed();

                // SAFETY: command buffer completed; scratch_b layout is
                // TopKCandidate { float logit; uint token_id; } — token_id at bytes [4..8].
                unsafe {
                    let ptr = scratch_b.contents() as *const u8;
                    let token_id_bytes = std::slice::from_raw_parts(ptr.add(4), 4);
                    u32::from_le_bytes([
                        token_id_bytes[0],
                        token_id_bytes[1],
                        token_id_bytes[2],
                        token_id_bytes[3],
                    ])
                }
            };

            // Mirror of sampling.rs:argmax_f32 — NaN never beats a real value.
            let cpu_argmax = |logits: &[f32]| -> u32 {
                let mut best_idx = 0u32;
                let mut best_val = f32::NEG_INFINITY;
                for (i, &v) in logits.iter().enumerate() {
                    if v > best_val {
                        best_val = v;
                        best_idx = i as u32;
                    }
                }
                best_idx
            };

            struct Case {
                name: &'static str,
                logits: Vec<f32>,
                expect_gpu_eq_cpu: bool,
            }

            // When all values are NaN the CPU returns 0 (initial best_idx) but the
            // GPU returns UINT_MAX (sentinel token_id).  This is a documented
            // divergence; in practice logits never contain only NaN at inference time.
            let cases: Vec<Case> = vec![
                Case {
                    name: "single element",
                    logits: vec![1.0f32],
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "small random (5 elem)",
                    logits: vec![0.1f32, 0.9, 0.3, 0.7, 0.5],
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "sorted descending (max first)",
                    logits: (0u32..256).rev().map(|i| i as f32).collect(),
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "reverse sorted (max last)",
                    logits: (0u32..256).map(|i| i as f32).collect(),
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "all same values (tie → lowest id = 0)",
                    logits: vec![1.5f32; 4096],
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "full vocab 248320 random",
                    logits: {
                        let mut rng = 42u64;
                        (0..248_320)
                            .map(|_| {
                                rng ^= rng << 13;
                                rng ^= rng >> 7;
                                rng ^= rng << 17;
                                ((rng as f64) / (u64::MAX as f64) * 2.0 - 1.0) as f32
                            })
                            .collect()
                    },
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "partial NaN (non-NaN max wins)",
                    logits: vec![1.0f32, f32::NAN, 5.0, f32::NAN, 3.0],
                    expect_gpu_eq_cpu: true,
                },
                Case {
                    name: "-Inf values (finite max wins)",
                    logits: vec![f32::NEG_INFINITY, 2.0f32, f32::NEG_INFINITY, 1.0],
                    expect_gpu_eq_cpu: true,
                },
            ];

            let mut failures = Vec::new();
            for case in &cases {
                let cpu = cpu_argmax(&case.logits);
                let gpu = gpu_argmax(&case.logits);
                let matches = gpu == cpu;
                if case.expect_gpu_eq_cpu && !matches {
                    failures.push(format!("MISMATCH {}: cpu={cpu} gpu={gpu}", case.name));
                }
            }

            assert!(
                failures.is_empty(),
                "GPU-CPU argmax parity failures:\n{}",
                failures.join("\n")
            );
        }

        fn tiny_metal_qwen35_fixture() -> (Qwen35Config, ModelWeights) {
            let hidden = 512usize;
            let intermediate = 64usize;
            let vocab = 64usize;
            let cfg = Qwen35Config {
                hidden_size: hidden,
                num_hidden_layers: 1,
                vocab_size: vocab,
                intermediate_size: intermediate,
                rms_norm_eps: 1e-6,
                num_attention_heads: 2,
                num_key_value_heads: 1,
                head_dim: 256,
                rope_theta: 10_000_000.0,
                partial_rotary_factor: 0.25,
                rope_parameters: None,
                linear_num_key_heads: 1,
                linear_num_value_heads: Some(1),
                linear_key_head_dim: 16,
                linear_value_head_dim: 16,
                linear_conv_kernel_dim: 4,
                num_experts: None,
                num_experts_per_tok: None,
                moe_intermediate_size: None,
                shared_expert_intermediate_size: None,
                output_router_logits: false,
                router_aux_loss_coef: None,
                tie_word_embeddings: true,
                mtp_num_hidden_layers: 0,
                mtp_use_dedicated_embeddings: false,
                full_attention_interval: 1,
                layer_types: vec![LayerType::FullAttention],
                layer_mask: vec![true],
                eos_token_id: (vocab - 1) as u32,
                max_position_embeddings: 128,
                quarot_rotation_seed: None,
            };

            let mut embed_tokens = vec![0.0f32; vocab * hidden];
            for token in 0..vocab {
                embed_tokens[token * hidden] = match token % 3 {
                    0 => -1.0,
                    1 => 0.0,
                    _ => 1.0,
                };
            }
            embed_tokens[42 * hidden] = 1.0;

            let common = CommonLayerWeights {
                input_layernorm: vec![1.0; hidden],
                post_attention_layernorm: vec![1.0; hidden],
                ffn: FeedForwardWeights::Dense(DenseFfnWeights {
                    gate_proj: vec![0.0; intermediate * hidden],
                    up_proj: vec![0.0; intermediate * hidden],
                    down_proj: vec![0.0; hidden * intermediate],
                }),
            };

            let full = FullAttentionLayerWeights {
                q_proj: vec![0.0; 2 * cfg.full_q_dim() * hidden],
                k_proj: vec![0.0; cfg.full_kv_dim() * hidden],
                v_proj: vec![0.0; cfg.full_kv_dim() * hidden],
                o_proj: vec![0.0; hidden * cfg.full_q_dim()],
                q_norm: vec![1.0; cfg.head_dim],
                k_norm: vec![1.0; cfg.head_dim],
            };

            let weights = ModelWeights {
                embed_tokens,
                lm_head: None,
                final_norm: vec![1.0; hidden],
                layers: vec![(AttentionWeights::Full(full), common)],
            };
            (cfg, weights)
        }

        fn rotate_embedding_rows_for_test(
            weights: &mut ModelWeights,
            hidden: usize,
            rot: &crate::quant::quarot::hadamard::RandomizedHadamard,
        ) {
            for row in weights.embed_tokens.chunks_exact_mut(hidden) {
                rot.apply(row).unwrap();
            }
        }

        fn synthetic_mtp_weights_for_test(device: &Device, cfg: &Qwen35Config) -> MetalMtpWeights {
            let hidden = cfg.hidden_size;
            let inter = cfg.intermediate_size;
            let q_dim = cfg.full_q_dim();
            let kv_dim = cfg.full_kv_dim();

            // fc shape: [hidden, 2*hidden]; identity on the embedding half so MTP
            // output equals the normed embedding when attention/MLP weights are zero.
            let mut fc = vec![0.0f32; hidden * 2 * hidden];
            for i in 0..hidden {
                fc[i * (2 * hidden) + i] = 1.0;
            }

            MetalMtpWeights {
                fc: make_buffer_f16(device, &fc, "test.mtp.fc"),
                pre_fc_norm_embedding: make_buffer(
                    device,
                    &vec![1.0; hidden],
                    "test.mtp.pre_fc_norm_embedding",
                ),
                pre_fc_norm_hidden: make_buffer(
                    device,
                    &vec![1.0; hidden],
                    "test.mtp.pre_fc_norm_hidden",
                ),
                layers: vec![MetalMtpLayerWeights {
                    input_layernorm: make_buffer(device, &vec![1.0; hidden], "test.mtp.input_ln"),
                    post_attention_layernorm: make_buffer(
                        device,
                        &vec![1.0; hidden],
                        "test.mtp.post_attn_ln",
                    ),
                    q_proj: make_buffer_f16(
                        device,
                        &vec![0.0; 2 * q_dim * hidden],
                        "test.mtp.q_proj",
                    ),
                    k_proj: make_buffer_f16(device, &vec![0.0; kv_dim * hidden], "test.mtp.k_proj"),
                    v_proj: make_buffer_f16(device, &vec![0.0; kv_dim * hidden], "test.mtp.v_proj"),
                    o_proj: make_buffer_f16(device, &vec![0.0; hidden * q_dim], "test.mtp.o_proj"),
                    q_norm: make_buffer(device, &vec![1.0; cfg.head_dim], "test.mtp.q_norm"),
                    k_norm: make_buffer(device, &vec![1.0; cfg.head_dim], "test.mtp.k_norm"),
                    mlp: MetalMtpDenseMlpWeights {
                        gate_proj: make_buffer_f16(
                            device,
                            &vec![0.0; inter * hidden],
                            "test.mtp.gate_proj",
                        ),
                        up_proj: make_buffer_f16(
                            device,
                            &vec![0.0; inter * hidden],
                            "test.mtp.up_proj",
                        ),
                        down_proj: make_buffer_f16(
                            device,
                            &vec![0.0; hidden * inter],
                            "test.mtp.down_proj",
                        ),
                    },
                }],
                norm: make_buffer(device, &vec![1.0; hidden], "test.mtp.norm"),
            }
        }

        fn metal_state_with_synthetic_mtp_for_test(
            weights: &ModelWeights,
            cfg: &Qwen35Config,
            rotation: Option<crate::quant::quarot::hadamard::RandomizedHadamard>,
        ) -> MetalQwen35State {
            let mut engine = MetalQwen35Engine::new(weights, cfg)
                .expect("tiny MetalQwen35Engine with MTP fixture constructs");
            engine.mtp_weights = Some(synthetic_mtp_weights_for_test(&engine.device, cfg));
            engine.quarot_rotation = rotation;
            let session = engine.new_session(16).expect("tiny MTP session constructs");
            MetalQwen35State {
                engine,
                session,
                lora: None,
                use_gdn_chunked: true,
                use_kv_f16: false,
                cross_turn_prefix_cache: MetalCrossTurnPrefixCache::default(),
                path_proof_enabled: false,
                path_proof: PathProofCounters::default(),
            }
        }

        // ADR-051 §"Verification" line 213: MTP draft-logit equivalence test.
        // Verifies that counter-rotating MTP inputs (apply_inverse) and re-rotating the
        // MTP output (apply) before the shared lm_head produces logits identical to the
        // unrotated reference path, within Metal f16/Q8 quantization tolerance.
        #[test]
        fn mtp_draft_logit_equivalence_with_quarot_counter_rotation() {
            let Some(_) = Device::system_default() else {
                return;
            };

            let (mut cfg, reference_weights) = tiny_metal_qwen35_fixture();
            cfg.mtp_num_hidden_layers = 1;

            let seed = 0x51_51_51_u64;
            let rotation =
                crate::quant::quarot::hadamard::RandomizedHadamard::new(seed, cfg.hidden_size)
                    .unwrap();

            // Build rotated weights independently (ModelWeights has no Clone).
            let (_, mut rotated_weights) = tiny_metal_qwen35_fixture();
            rotate_embedding_rows_for_test(&mut rotated_weights, cfg.hidden_size, &rotation);

            let mut reference_state =
                metal_state_with_synthetic_mtp_for_test(&reference_weights, &cfg, None);
            let mut rotated_state = metal_state_with_synthetic_mtp_for_test(
                &rotated_weights,
                &cfg,
                Some(rotation.clone()),
            );

            // Inject a realistic pre-final hidden state. Both paths get the same
            // mathematical vector; the rotated path gets R applied so that
            // apply_inverse inside mtp_forward_one recovers the original.
            let h_original: Vec<f32> = (0..cfg.hidden_size)
                .map(|i| ((i as f32) * 0.013).sin() * 0.25)
                .collect();
            let mut h_rotated = h_original.clone();
            rotation.apply(&mut h_rotated).unwrap();
            reference_state.session.last_pre_final_hidden = h_original;
            rotated_state.session.last_pre_final_hidden = h_rotated;

            let reference = reference_state.mtp_forward_one(42_u32, 0_usize);
            let rotated = rotated_state.mtp_forward_one(42_u32, 0_usize);

            assert_eq!(reference.logits.len(), cfg.vocab_size);
            assert_eq!(rotated.logits.len(), cfg.vocab_size);
            let max_abs_diff = reference
                .logits
                .iter()
                .zip(rotated.logits.iter())
                .map(|(a, b)| (a - b).abs())
                .fold(0.0_f32, f32::max);
            // Tolerance is wider than the non-rotated golden-logit tests (1e-4) because
            // the Hadamard rotation spreads each embedding row across all 512 dimensions,
            // and the subsequent f16 roundtrip in embed_tokens + RMSNorm amplification
            // (~sqrt(hidden)) introduces ~0.02 per-logit error on the rotated path.
            // A missing or wrong counter-rotation would produce O(10) error, so 0.05
            // is tight enough to catch implementation defects.
            assert!(
                max_abs_diff < 0.05,
                "MTP draft logits diverged after QuaRot counter-rotation: max_abs_diff={max_abs_diff}"
            );
        }

        #[test]
        fn test_metal_qwen35_golden_logit_snapshot_forward_step_token_42_pos_0() {
            let Some(_) = Device::system_default() else {
                return;
            };
            let (cfg, weights) = tiny_metal_qwen35_fixture();
            let mut state = MetalQwen35State::new(&weights, &cfg, 16)
                .expect("tiny MetalQwen35State fixture constructs");

            let logits = state.forward_step(42, 0);
            assert_eq!(logits.len(), cfg.vocab_size);
            let actual = &logits[..10];
            // Math: token 42's embedding is one-hot: x[0]=1.0, x[1..]=0.0.
            // All attention and FFN weights are zero → residual stream equals the
            // raw embedding at every stage. final_norm then applies the shifted
            // RMSNorm (qwen35_rms_norm convention: output = x * (1 + gamma) / rms(x)).
            // With final_norm=[1.0] the scale is (1+1.0)=2; identity is gamma=0.
            //   rms(x) = sqrt(1/512),  output[0] = 1.0 * (1+1.0) * sqrt(512) = 2*sqrt(512) ≈ 45.254.
            // Tied lm_head col-0 pattern is [-1,0,1,-1,0,1,...], so logits ≈ ±45.25 / 0.
            // (Issue #31: the original golden ±22.62 assumed plain-gamma; ±45.24 is correct.)
            let expected = [
                -45.243256_f32,
                0.0,
                45.243256,
                -45.243256,
                0.0,
                45.243256,
                -45.243256,
                0.0,
                45.243256,
                -45.243256,
            ];
            let max_abs_diff = actual
                .iter()
                .zip(expected.iter())
                .map(|(a, e)| (a - e).abs())
                .fold(0.0_f32, f32::max);
            assert!(
                max_abs_diff < 1e-4,
                "golden first-10 logits changed: actual={actual:?} expected={expected:?} max_abs_diff={max_abs_diff}"
            );
        }

        #[test]
        fn test_metal_qwen35_kv_cache_determinism_replay_5_tokens() {
            let Some(_) = Device::system_default() else {
                return;
            };
            let (cfg, weights) = tiny_metal_qwen35_fixture();
            let tokens = [42_u32, 7, 13, 8, 42];
            let mut state = MetalQwen35State::new(&weights, &cfg, 16)
                .expect("tiny MetalQwen35State fixture constructs");

            // First pass
            let mut first_logits: Vec<Vec<f32>> = Vec::new();
            for &token in &tokens {
                let pos = state.session.kv_cache.seq_len;
                let logits = state.forward_step(token, pos);
                assert_eq!(
                    state.session.kv_cache.seq_len,
                    pos + 1,
                    "forward_step must advance seq_len exactly once"
                );
                first_logits.push(logits);
            }
            let first_seq_len = state.session.kv_cache.seq_len;

            state.reset_state();

            // Second pass (replay)
            let mut second_logits: Vec<Vec<f32>> = Vec::new();
            for &token in &tokens {
                let pos = state.session.kv_cache.seq_len;
                let logits = state.forward_step(token, pos);
                assert_eq!(
                    state.session.kv_cache.seq_len,
                    pos + 1,
                    "forward_step must advance seq_len exactly once"
                );
                second_logits.push(logits);
            }
            let second_seq_len = state.session.kv_cache.seq_len;

            assert_eq!(first_seq_len, tokens.len(), "first pass seq_len");
            assert_eq!(second_seq_len, tokens.len(), "second pass seq_len");
            for (step, (first, second)) in first_logits.iter().zip(second_logits.iter()).enumerate()
            {
                let max_abs_diff = first
                    .iter()
                    .zip(second.iter())
                    .map(|(a, b)| (a - b).abs())
                    .fold(0.0_f32, f32::max);
                assert!(
                    max_abs_diff < 1e-4,
                    "replay logits diverged at step {step}: max_abs_diff={max_abs_diff}"
                );
            }
        }

        /// Issue #252 (#238 follow-up): runtime capability probe for the f16
        /// KV-cache Metal path. GitHub's hosted `macos-latest` runner exposes a
        /// PARAVIRTUAL Metal GPU (not a real Apple7 device), so this test must
        /// NOT gate on `supports_family(Apple7)` — it gates on whether the f16
        /// KV kernels actually construct and execute, and fails loudly
        /// (LATTICE_METAL_TEST_ENFORCE=1) instead of skip-passing when a Metal
        /// device is absent.
        #[test]
        fn f16_kv_metal_path_executes_and_reports_capability() {
            let enforce = std::env::var_os("LATTICE_METAL_TEST_ENFORCE").is_some();
            let Some(_) = Device::system_default() else {
                eprintln!("[METAL_F16_KV_CAPABILITY] supported=false reason=no_metal_device");
                assert!(
                    !enforce,
                    "LATTICE_METAL_TEST_ENFORCE=1 but no Metal device present"
                );
                return;
            };

            assert!(
                matches!(
                    std::env::var("LATTICE_KV_F16").as_deref(),
                    Ok("1") | Ok("true")
                ),
                "f16 KV Metal probe must run with LATTICE_KV_F16=1"
            );
            assert!(
                matches!(
                    std::env::var("LATTICE_METAL_PATH_PROOF").as_deref(),
                    Ok("1") | Ok("true")
                ),
                "f16 KV Metal probe must run with LATTICE_METAL_PATH_PROOF=1"
            );

            let (cfg, weights) = tiny_metal_qwen35_fixture();
            let mut state = match MetalQwen35State::new(&weights, &cfg, 16) {
                Ok(state) => state,
                Err(err) => {
                    eprintln!(
                        "[METAL_F16_KV_CAPABILITY] supported=false reason=construct_failed error={err}"
                    );
                    panic!("f16 KV Metal capability probe failed during state construction: {err}");
                }
            };

            assert!(state.use_kv_f16, "state did not enable f16 KV cache");
            assert!(state.session.kv_cache.kv_f16, "KV cache layout is not f16");
            assert!(state.path_proof_enabled, "path-proof counters are disabled");

            let expected_kv_bytes = 16 * cfg.full_kv_dim() * 2;
            assert_eq!(
                state.session.kv_cache.k_bufs[0].length() as usize,
                expected_kv_bytes,
                "K cache buffer must use f16 element size"
            );

            state.reset_path_proof_counters();
            let _ = state.forward_prefill(&[1, 2, 3]);
            let decode_pos = state.session.kv_cache.seq_len;
            let _ = state.forward_step(4, decode_pos);

            let proof = state.path_proof_snapshot();
            eprintln!(
                "[METAL_F16_KV_CAPABILITY] supported=true kv_f16={} prefill_kv_batch={} prefill_attn_batched={} decode_kv_copy={} decode_attn_direct={} decode_attn_split_partial={} decode_attn_split_reduce={}",
                proof.kv_f16,
                proof.prefill_kv_batch,
                proof.prefill_attn_batched,
                proof.decode_kv_copy,
                proof.decode_attn_direct,
                proof.decode_attn_split_partial,
                proof.decode_attn_split_reduce,
            );

            assert!(proof.kv_f16, "path proof did not report kv_f16=true");
            assert!(
                proof.prefill_kv_batch > 0,
                "f16 batch KV write did not execute"
            );
            assert!(
                proof.prefill_attn_batched > 0,
                "f16 batched prefill attention did not execute"
            );
            assert!(
                proof.decode_kv_copy > 0,
                "f16 decode KV copy did not execute"
            );
            assert!(
                proof.decode_attn_direct > 0
                    || (proof.decode_attn_split_partial > 0 && proof.decode_attn_split_reduce > 0),
                "f16 decode attention did not execute"
            );
        }

        #[test]
        fn test_metal_qwen35_engine_session_isolation() {
            let Some(_) = Device::system_default() else {
                return;
            };
            let (cfg, weights) = tiny_metal_qwen35_fixture();

            // Build engine, then create two independent sessions from it.
            let engine = MetalQwen35Engine::new(&weights, &cfg)
                .expect("MetalQwen35Engine constructs from tiny fixture");
            let session_a = engine.new_session(16).expect("session_a constructs");
            let session_b = engine.new_session(16).expect("session_b constructs");

            // Both sessions start at position 0.
            assert_eq!(session_a.position, 0, "session_a starts at position 0");
            assert_eq!(session_b.position, 0, "session_b starts at position 0");
            assert_eq!(
                session_a.kv_cache.seq_len, 0,
                "session_a kv_cache starts empty"
            );
            assert_eq!(
                session_b.kv_cache.seq_len, 0,
                "session_b kv_cache starts empty"
            );

            // Wrap engine + session_a into a full state and run forward steps.
            let mut state_a = MetalQwen35State {
                engine,
                session: session_a,
                lora: None,
                use_gdn_chunked: true,
                use_kv_f16: false,
                cross_turn_prefix_cache: MetalCrossTurnPrefixCache::default(),
                path_proof_enabled: false,
                path_proof: PathProofCounters::default(),
            };
            let _logits = state_a.forward_step(42, 0);
            let _logits = state_a.forward_step(7, 1);

            // session_a (inside state_a) has advanced.
            assert_eq!(
                state_a.session.kv_cache.seq_len, 2,
                "state_a advanced 2 steps"
            );

            // Create a fresh session from the same engine — must start at 0.
            let fresh_session = state_a
                .engine
                .new_session(16)
                .expect("fresh session constructs");
            assert_eq!(
                fresh_session.position, 0,
                "fresh session position independent of state_a"
            );
            assert_eq!(
                fresh_session.kv_cache.seq_len, 0,
                "fresh session kv_cache independent"
            );

            // session_b was never touched; its state should match a fresh session.
            assert_eq!(
                session_b.position, 0,
                "session_b untouched by state_a steps"
            );
            assert_eq!(
                session_b.kv_cache.seq_len, 0,
                "session_b kv_cache untouched"
            );
        }

