// ---------------------------------------------------------------------------
// Differential unit tests for `mtp_greedy_round`.
//
// These tests run on every platform without Metal GPU hardware (no cfg gate).
// They compare the output of a tiny plain-greedy oracle against the sequence
// produced by driving `mtp_greedy_round` with the same synthetic target
// logits, across hand-constructed cases and a seeded randomised sweep.
//
// EOS-faithful contract (all three terminal cases A/B/C must match oracle):
//   A: prefill argmax is EOS → oracle emits [EOS]; simulation must also emit [EOS].
//   B: accept + bonus is stop → oracle emits [..., pending, draft, bonus];
//      simulation must emit the same (bonus emitted as trailing stop token).
//   C: reject + replacement is stop → oracle emits [..., pending, replacement];
//      simulation must emit the same.
// ---------------------------------------------------------------------------
#[cfg(test)]
mod mtp_load_warning_tests {
    use super::mtp_missing_weights_warning;
    use std::path::Path;

    #[test]
    fn requested_missing_mtp_weights_warns_and_disables() {
        let warning = mtp_missing_weights_warning(
            true,
            false,
            Some(Path::new("mtp_layers_0_self_attn_q_proj_weight.f16")),
        );

        assert_eq!(
            warning.as_deref(),
            Some(
                "LATTICE_MTP=1 requested MTP, but first required weight file is missing: mtp_layers_0_self_attn_q_proj_weight.f16; MTP is DISABLED, decode falls back to the plain path."
            )
        );
    }

    #[test]
    fn loaded_or_not_requested_mtp_weights_do_not_warn() {
        let path = Some(Path::new("mtp_layers_0_self_attn_q_proj_weight.f16"));

        assert_eq!(mtp_missing_weights_warning(true, true, path), None);
        assert_eq!(mtp_missing_weights_warning(false, false, path), None);
    }
}

#[cfg(test)]
mod mtp_greedy_round_tests {
    use super::{MtpRoundOutcome, mtp_greedy_round};

    const EOS: u32 = 2;

    fn is_stop(id: u32) -> bool {
        id == EOS
    }

    // -----------------------------------------------------------------------
    // Plain-greedy oracle: given a sequence of per-position logit vectors,
    // greedily pick argmax at each position, push to output, stop when
    // argmax is a stop token (including that stop token), or at max_len.
    //
    // Matches generate.rs: generated_ids.push(token) precedes the EOS check,
    // so the stop token is always present in the output.
    // -----------------------------------------------------------------------
    fn plain_greedy_oracle(logit_rows: &[Vec<f32>], max_len: usize) -> Vec<u32> {
        let mut out = Vec::new();
        for row in logit_rows.iter().take(max_len) {
            let token = argmax(row);
            out.push(token);
            if is_stop(token) {
                break;
            }
        }
        out
    }

    fn argmax(logits: &[f32]) -> u32 {
        logits
            .iter()
            .copied()
            .enumerate()
            .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal))
            .map(|(i, _)| i as u32)
            .unwrap_or(0)
    }

    // -----------------------------------------------------------------------
    // MTP simulation: drives `mtp_greedy_round` with the same synthetic
    // target logits used by the oracle.
    //
    // Alignment with the oracle:
    //   logit_rows[i] = target's logit vector for position i.
    //   argmax(logit_rows[0]) = first pending token (prefill argmax).
    //   argmax(logit_rows[i+1]) = target's prediction for pos+1 from pos i.
    //
    // Each MTP round at pos i:
    //   pending          = argmax(logit_rows[i])
    //   draft            = draft_seq[i]
    //   target_logits_0  = logit_rows[i+1]   (verify pos i+1)
    //   accepted         = draft == argmax(target_logits_0)
    //   bonus            = accepted ? argmax(logit_rows[i+2])
    //                               : argmax(logit_rows[i+1])
    //
    // Case A (pending is stop): emit [pending], stop — mirrors the FIXED
    // Metal loop (generate.rs: first_token is pushed before EOS check).
    // -----------------------------------------------------------------------
    fn simulate_mtp(logit_rows: &[Vec<f32>], draft_seq: &[u32], max_len: usize) -> Vec<u32> {
        assert!(
            !logit_rows.is_empty(),
            "simulate_mtp: need at least one logit row"
        );
        let mut out: Vec<u32> = Vec::new();
        let mut pos = 0usize; // index into logit_rows for the current pending
        let mut draft_idx = 0usize; // sequential index into draft_seq

        loop {
            if out.len() >= max_len {
                break;
            }
            let pending_token = argmax(&logit_rows[pos]);

            // Case A: pending is a stop token.  The fixed Metal loop emits it
            // (matches generate.rs: push first_token then check EOS).  For
            // subsequent rounds, mtp_greedy_round guarantees EmitAndContinue only
            // returns non-stop next_pending, so this branch fires only at pos=0.
            if is_stop(pending_token) {
                out.push(pending_token);
                break;
            }

            // Need at least logit_rows[pos+1] for verify.
            if pos + 1 >= logit_rows.len() {
                out.push(pending_token);
                break;
            }

            let draft_token = if draft_idx < draft_seq.len() {
                draft_seq[draft_idx]
            } else {
                // No more drafts: fall back to pushing pending and stopping.
                out.push(pending_token);
                break;
            };
            draft_idx += 1;

            let target_logits_0 = &logit_rows[pos + 1];
            let accepted = draft_token == argmax(target_logits_0);
            let bonus_token = if accepted {
                if pos + 2 < logit_rows.len() {
                    argmax(&logit_rows[pos + 2])
                } else {
                    0 // no further prediction available; use 0 (non-stop)
                }
            } else {
                argmax(target_logits_0)
            };

            match mtp_greedy_round(pending_token, draft_token, accepted, bonus_token, is_stop) {
                MtpRoundOutcome::EmitAndStop(tokens) => {
                    // Mirror the real call site: clip the emission to the remaining
                    // budget so MTP never exceeds max_len (plain greedy caps exactly).
                    let remaining = max_len - out.len();
                    out.extend_from_slice(&tokens[..tokens.len().min(remaining)]);
                    break;
                }
                MtpRoundOutcome::EmitAndContinue { emit, next_pending } => {
                    let remaining = max_len - out.len();
                    out.extend_from_slice(&emit[..emit.len().min(remaining)]);
                    if out.len() >= max_len {
                        break;
                    }
                    // Advance pos: accept advances by 2, reject by 1.
                    pos = if accepted { pos + 2 } else { pos + 1 };
                    let _ = next_pending; // value verified via logit_rows[pos]
                }
            }
        }
        out
    }

    // -----------------------------------------------------------------------
    // Case A: prefill argmax is a stop token.
    // Oracle: [EOS].  MTP (FIXED): [EOS].
    // Old MTP code returned token_ids: vec![] (generated_tokens: 0) — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_case_a_prefill_eos() {
        // logit_rows[0] argmax is EOS — the very first pending is a stop.
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(EOS, 5), // pos0 → EOS
            make_logit(10, 5),  // pos1 → 10 (never reached)
        ];
        let draft_seq = vec![10u32]; // draft never consulted
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        // Oracle: push EOS, then stop → [EOS].
        assert_eq!(oracle, vec![EOS], "oracle sanity: prefill EOS yields [EOS]");

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        // Fixed MTP: pending_first = EOS → emit [EOS], return.
        assert_eq!(mtp, vec![EOS], "case A: mtp must emit [EOS] not []");
        assert_eq!(
            oracle, mtp,
            "case A: full oracle==mtp equality required; mtp={mtp:?}"
        );
    }

    // -----------------------------------------------------------------------
    // Case B: accept + bonus is stop.
    // Oracle: [pending, draft, EOS].  MTP (FIXED): [pending, draft, EOS].
    // Old mtp_greedy_round returned EmitAndStop([pending, draft]) — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_case_b_accept_bonus_stop() {
        // pending=10, draft=20 (accepted), bonus=EOS.
        // accept: target[1]=20, target[2]=EOS.
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),  // pos0 → 10 (pending)
            make_logit(20, 5),  // pos1 → 20 (target agrees with draft)
            make_logit(EOS, 5), // pos2 → EOS (bonus)
        ];
        let draft_seq = vec![20u32];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        // Oracle: push 10, push 20, push EOS, stop → [10, 20, EOS].
        assert_eq!(oracle, vec![10, 20, EOS], "case B oracle sanity");

        // Verify the pure function directly.
        let outcome = mtp_greedy_round(
            10,   // pending
            20,   // draft (accepted)
            true, // accepted
            EOS,  // bonus is stop
            is_stop,
        );
        assert_eq!(
            outcome,
            MtpRoundOutcome::EmitAndStop(vec![10, 20, EOS]),
            "case B: accept+bonus-stop must emit [pending, draft, bonus]"
        );

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        assert_eq!(mtp, vec![10, 20, EOS], "case B: mtp must match oracle");
        assert_eq!(
            oracle, mtp,
            "case B: full oracle==mtp equality required; mtp={mtp:?}"
        );
    }

    // -----------------------------------------------------------------------
    // Case C: reject + replacement is stop.
    // Oracle: [pending, EOS].  MTP (FIXED): [pending, EOS].
    // Old mtp_greedy_round returned EmitAndStop([pending]) — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_case_c_reject_bonus_stop() {
        // pending=10, draft=99 (wrong), target says EOS at pos1.
        // reject: target[1]=EOS, bonus=EOS.
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),  // pos0 → 10 (pending)
            make_logit(EOS, 5), // pos1 → EOS (target's own choice = EOS)
        ];
        let draft_seq = vec![99u32]; // wrong draft
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        // Oracle: push 10, push EOS, stop → [10, EOS].
        assert_eq!(oracle, vec![10, EOS], "case C oracle sanity");

        // Verify the pure function directly.
        let outcome = mtp_greedy_round(
            10,    // pending
            99,    // draft (rejected)
            false, // not accepted
            EOS,   // bonus = target's replacement = EOS
            is_stop,
        );
        assert_eq!(
            outcome,
            MtpRoundOutcome::EmitAndStop(vec![10, EOS]),
            "case C: reject+bonus-stop must emit [pending, bonus]"
        );

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        assert_eq!(mtp, vec![10, EOS], "case C: mtp must match oracle");
        assert_eq!(
            oracle, mtp,
            "case C: full oracle==mtp equality required; mtp={mtp:?}"
        );
    }

    // -----------------------------------------------------------------------
    // Hand-constructed: All non-stop tokens, draft always accepted.
    // Oracle and MTP should agree on the first `max_len` tokens.
    // -----------------------------------------------------------------------
    #[test]
    fn test_all_accepted_no_stop() {
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5), // pos0 → 10
            make_logit(20, 5), // pos1 → 20
            make_logit(30, 5), // pos2 → 30
            make_logit(40, 5), // pos3 → 40
        ];
        let draft_seq = vec![20u32, 30, 40];
        let max_len = 4;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        assert_eq!(
            oracle, mtp,
            "all-accept non-stop: oracle={oracle:?} mtp={mtp:?}"
        );
    }

    // -----------------------------------------------------------------------
    // Hand-constructed: Draft always rejected, no stop tokens.
    // Oracle and MTP output must agree.
    // -----------------------------------------------------------------------
    #[test]
    fn test_all_rejected_no_stop() {
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),
            make_logit(20, 5),
            make_logit(30, 5),
            make_logit(40, 5),
        ];
        let draft_seq = vec![99u32, 99, 99];
        let max_len = 4;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        assert_eq!(
            oracle, mtp,
            "all-reject non-stop: oracle={oracle:?} mtp={mtp:?}"
        );
    }

    // -----------------------------------------------------------------------
    // Hand-constructed: target emits EOS via the accept+bonus-stop path.
    // After fix B, oracle and MTP both emit [10, 20, EOS].
    // -----------------------------------------------------------------------
    #[test]
    fn test_target_eos_via_bonus() {
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),  // pos0 → 10
            make_logit(20, 5),  // pos1 → 20 (draft correct → accepted)
            make_logit(EOS, 5), // pos2 → EOS (bonus)
        ];
        let draft_seq = vec![20u32, 99];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, 20, EOS], "oracle: [10, 20, EOS]");

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        // Round 0: pending=10, draft=20, accepted, bonus=EOS
        //   → mtp_greedy_round(10, 20, true, EOS, is_stop)
        //   → EmitAndStop([10, 20, EOS])   (case B fix)
        assert_eq!(
            mtp,
            vec![10, 20, EOS],
            "after case B fix, mtp must equal oracle"
        );
        assert_eq!(oracle, mtp);
    }

    // -----------------------------------------------------------------------
    // KEY REGRESSION TEST (concern #2 of #237):
    // Draft proposes EOS but the target argmax is NOT a stop token.
    // OLD CODE: short-circuit fires, emits [pending], stops early → WRONG.
    // NEW CODE: verify runs, draft rejected, continue with target replacement.
    // -----------------------------------------------------------------------
    #[test]
    fn test_draft_eos_but_target_non_stop() {
        // Sequence: target wants 10 → 20 → 30 → EOS.
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),  // pos0 → 10
            make_logit(20, 5),  // pos1 → 20  (draft proposes EOS here — WRONG)
            make_logit(30, 5),  // pos2 → 30
            make_logit(EOS, 5), // pos3 → EOS
        ];
        let draft_seq = vec![EOS, 99u32, 99];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, 20, 30, EOS], "oracle sanity check");

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        // Round 0: pending=10, draft=EOS, target[1]=20 (non-stop) → rejected.
        //   bonus = 20.  EmitAndContinue([10], 20).  pos→1.
        // Round 1: pending=20, draft=99, target[2]=30 → rejected.
        //   bonus = 30.  EmitAndContinue([20], 30).  pos→2.
        // Round 2: pending=30, draft=99, target[3]=EOS → rejected.
        //   bonus = EOS.  EmitAndStop([30, EOS])   ← case C fix.
        // MTP output = [10, 20, 30, EOS].
        assert_eq!(
            mtp,
            vec![10, 20, 30, EOS],
            "draft-EOS-but-target-non-stop: must match oracle; got {mtp:?}"
        );
        assert_eq!(oracle, mtp);
        // Confirm it does NOT equal [10] (old short-circuit regression).
        assert_ne!(
            mtp,
            vec![10],
            "output must not be [10] (old short-circuit regression)"
        );
    }

    // -----------------------------------------------------------------------
    // Hand-constructed: Draft proposes EOS and target AGREES.
    // MTP must emit [pending, EOS] and stop (accept+draft-is-stop path).
    // -----------------------------------------------------------------------
    #[test]
    fn test_draft_eos_accepted() {
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),  // pos0 → 10 (pending)
            make_logit(EOS, 5), // pos1 → EOS (target agrees with draft)
            make_logit(30, 5),  // pos2 → 30 (bonus, irrelevant once EOS accepted)
        ];
        let draft_seq = vec![EOS];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, EOS]);

        let outcome = mtp_greedy_round(
            10,   // pending
            EOS,  // draft (accepted: target[1]=EOS)
            true, // accepted
            30,   // bonus (irrelevant — draft is the stop)
            is_stop,
        );
        assert_eq!(
            outcome,
            MtpRoundOutcome::EmitAndStop(vec![10, EOS]),
            "accepted draft-EOS must emit [pending, EOS] and stop"
        );

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        assert_eq!(mtp, vec![10, EOS], "accepted draft-EOS: mtp={mtp:?}");
        assert_eq!(oracle, mtp);
    }

    // -----------------------------------------------------------------------
    // Mixed: some accepted, some rejected, EOS at the end via case C.
    // After fixes, oracle and MTP agree fully including EOS.
    // -----------------------------------------------------------------------
    #[test]
    fn test_mixed_accept_reject_then_eos() {
        let logit_rows: Vec<Vec<f32>> = vec![
            make_logit(10, 5),  // pos0 → 10
            make_logit(20, 5),  // pos1 → 20 (draft correct)
            make_logit(30, 5),  // pos2 → 30 (draft wrong)
            make_logit(40, 5),  // pos3 → 40 (draft wrong)
            make_logit(EOS, 5), // pos4 → EOS
        ];
        let draft_seq = vec![20u32, 99, 99];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, 20, 30, 40, EOS]);

        let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);
        // Round 0: pending=10, draft=20, accepted, bonus=30 (non-stop)
        //   → EmitAndContinue([10, 20], 30), pos=2
        // Round 1: pending=30, draft=99, rejected, bonus=40 (non-stop)
        //   → EmitAndContinue([30], 40), pos=3
        // Round 2: pending=40, draft=99, rejected, bonus=EOS (stop)
        //   → EmitAndStop([40, EOS])   ← case C fix
        // MTP output = [10, 20, 30, 40, EOS].
        assert_eq!(
            mtp,
            vec![10, 20, 30, 40, EOS],
            "mixed: mtp must fully match oracle"
        );
        assert_eq!(oracle, mtp);
    }

    // -----------------------------------------------------------------------
    // CAP-EDGE REGRESSION (codex finding #1 on PR #287):
    // A round can emit up to 3 tokens (case B). When max_new_tokens lands
    // mid-emission, the call site must clip so MTP never exceeds the cap —
    // plain greedy `generate()` stops at the cap even before an EOS.
    // -----------------------------------------------------------------------
    #[test]
    fn test_cap_clips_case_b_before_bonus() {
        // Case B logits: [10, 20, EOS]; uncapped MTP would emit [10, 20, EOS].
        let logit_rows: Vec<Vec<f32>> =
            vec![make_logit(10, 5), make_logit(20, 5), make_logit(EOS, 5)];
        let draft_seq = vec![20u32];

        // max_len = 2: cap lands before the bonus EOS.
        let oracle = plain_greedy_oracle(&logit_rows, 2);
        assert_eq!(oracle, vec![10, 20], "oracle caps at 2 tokens, no EOS");
        let mtp = simulate_mtp(&logit_rows, &draft_seq, 2);
        assert_eq!(
            mtp,
            vec![10, 20],
            "case B must clip to [10, 20] at max_len=2"
        );
        assert_eq!(oracle, mtp);

        // max_len = 1: only the pending token fits.
        let oracle1 = plain_greedy_oracle(&logit_rows, 1);
        assert_eq!(oracle1, vec![10]);
        let mtp1 = simulate_mtp(&logit_rows, &draft_seq, 1);
        assert_eq!(mtp1, vec![10], "case B must clip to [10] at max_len=1");
        assert_eq!(oracle1, mtp1);
    }

    #[test]
    fn test_cap_clips_case_c_max_len_1() {
        // Case C: pending=10, draft wrong, target replacement is EOS.
        let logit_rows: Vec<Vec<f32>> = vec![make_logit(10, 5), make_logit(EOS, 5)];
        let draft_seq = vec![99u32];
        let oracle = plain_greedy_oracle(&logit_rows, 1);
        assert_eq!(oracle, vec![10]);
        let mtp = simulate_mtp(&logit_rows, &draft_seq, 1);
        assert_eq!(mtp, vec![10], "case C must clip to [10] at max_len=1");
        assert_eq!(oracle, mtp);
    }

    #[test]
    fn test_cap_clips_continue_emit() {
        // accept + non-stop bonus → EmitAndContinue([pending, draft]); cap=1 clips to [pending].
        let logit_rows: Vec<Vec<f32>> =
            vec![make_logit(10, 5), make_logit(20, 5), make_logit(30, 5)];
        let draft_seq = vec![20u32, 30];
        let oracle = plain_greedy_oracle(&logit_rows, 1);
        assert_eq!(oracle, vec![10]);
        let mtp = simulate_mtp(&logit_rows, &draft_seq, 1);
        assert_eq!(
            mtp,
            vec![10],
            "EmitAndContinue must clip to [10] at max_len=1"
        );
        assert_eq!(oracle, mtp);
    }

    // -----------------------------------------------------------------------
    // Randomised / property-style sweep: seeded RNG, arbitrary draft choices.
    //
    // With all three EOS-faithful fixes (A/B/C), `simulate_mtp` should produce
    // token-for-token identical output to `plain_greedy_oracle` across all
    // trials, including those where stop tokens appear at any position.
    //
    // The sweep also includes trials where logit_rows[0] is EOS (case A).
    // max_len is set large (20) so that natural EOS-stop is reached before
    // the cap, keeping EOS-faithfulness under test rather than cap behavior.
    // -----------------------------------------------------------------------
    #[test]
    fn test_randomised_sweep() {
        let mut rng = Lcg::new(0xdeadbeef_cafebabe);

        let vocab_size = 8usize; // tiny vocab; EOS=2
        let trials = 400;

        for trial in 0..trials {
            let seq_len = (rng.next_u64() % 6 + 2) as usize; // 2..=7
            // Large max_len so EOS-stop is reached before cap in most trials.
            let max_len = 20;

            // Random logit rows — stop tokens may appear at any position.
            let logit_rows: Vec<Vec<f32>> = (0..=seq_len)
                .map(|_| {
                    let winner = (rng.next_u64() % vocab_size as u64) as usize;
                    let mut row = vec![0.0f32; vocab_size];
                    row[winner] = 10.0;
                    row
                })
                .collect();

            // Random draft sequence (may propose EOS at any position).
            let draft_seq: Vec<u32> = (0..seq_len)
                .map(|_| (rng.next_u64() % vocab_size as u64) as u32)
                .collect();

            let oracle = plain_greedy_oracle(&logit_rows, max_len);
            let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);

            assert_eq!(
                oracle,
                mtp,
                "trial {trial}: oracle != mtp\n  logit_winners={:?}\n  draft_seq={:?}\n  oracle={:?}\n  mtp={:?}",
                logit_rows.iter().map(|r| argmax(r)).collect::<Vec<_>>(),
                draft_seq,
                oracle,
                mtp
            );
        }
    }

    // -----------------------------------------------------------------------
    // Randomised sweep with SMALL caps: stresses the emission-clip path so MTP
    // never exceeds max_len even when a round wants to emit 2-3 tokens.
    // -----------------------------------------------------------------------
    #[test]
    fn test_randomised_sweep_small_cap() {
        let mut rng = Lcg::new(0x0123_4567_89ab_cdef);
        let vocab_size = 6usize; // EOS=2, frequent stops
        let trials = 400;

        for trial in 0..trials {
            let seq_len = (rng.next_u64() % 6 + 2) as usize; // 2..=7
            let max_len = (rng.next_u64() % 4 + 1) as usize; // 1..=4 — cap often bites mid-round

            let logit_rows: Vec<Vec<f32>> = (0..=seq_len)
                .map(|_| {
                    let winner = (rng.next_u64() % vocab_size as u64) as usize;
                    let mut row = vec![0.0f32; vocab_size];
                    row[winner] = 10.0;
                    row
                })
                .collect();
            let draft_seq: Vec<u32> = (0..seq_len)
                .map(|_| (rng.next_u64() % vocab_size as u64) as u32)
                .collect();

            let oracle = plain_greedy_oracle(&logit_rows, max_len);
            let mtp = simulate_mtp(&logit_rows, &draft_seq, max_len);

            assert!(
                mtp.len() <= max_len,
                "trial {trial}: mtp exceeded cap {max_len}: {mtp:?}"
            );
            assert_eq!(
                oracle,
                mtp,
                "trial {trial} (max_len={max_len}): oracle != mtp\n  winners={:?}\n  draft={:?}\n  oracle={:?}\n  mtp={:?}",
                logit_rows.iter().map(|r| argmax(r)).collect::<Vec<_>>(),
                draft_seq,
                oracle,
                mtp
            );
        }
    }

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------

    /// Build a logit vector of size 100 with `winner` at logit 10.0.
    fn make_logit(winner: u32, _high: u32) -> Vec<f32> {
        let size = 100usize;
        let mut v = vec![0.0f32; size];
        if (winner as usize) < size {
            v[winner as usize] = 10.0;
        }
        v
    }

    /// Minimal deterministic LCG — no external crate needed.
    struct Lcg(u64);
    impl Lcg {
        fn new(seed: u64) -> Self {
            Self(seed)
        }
        fn next_u64(&mut self) -> u64 {
            self.0 = self
                .0
                .wrapping_mul(6364136223846793005)
                .wrapping_add(1442695040888963407);
            self.0
        }
    }

    // -----------------------------------------------------------------------
    // FIX 1: EmitAndStop `stopped` semantics.
    //
    // `generate_greedy_mtp` (under #[cfg(feature="metal-gpu")]) computes:
    //
    //   let emit_len = tokens.len().min(remaining);
    //   generated_ids.extend_from_slice(&tokens[..emit_len]);
    //   stopped = emit_len == tokens.len();   // ← FIX 1
    //
    // The pre-fix code was `stopped = true` unconditionally, which is wrong when
    // the budget clips the emission so the stop token (last element of `tokens`)
    // is never actually pushed — in that case the reason for termination is
    // the length cap, not the stop condition.
    //
    // `generate_greedy_mtp` requires Metal hardware and cannot be called from
    // `cargo test` (no GPU). `simulate_mtp_with_stopped` mirrors the call-site
    // logic exactly; tests here are mutation-sensitive against that logic.
    //
    // Mutation-sensitivity: change `stopped = emit_len == tokens.len()` in
    // `simulate_mtp_with_stopped` below back to `stopped = true` → both
    // cap-clipped tests go RED (expected false, got true).
    // -----------------------------------------------------------------------
    fn simulate_mtp_with_stopped(
        logit_rows: &[Vec<f32>],
        draft_seq: &[u32],
        max_len: usize,
    ) -> (Vec<u32>, bool) {
        let mut out: Vec<u32> = Vec::new();
        let mut stopped = false;
        let mut pos = 0usize;
        let mut draft_idx = 0usize;

        loop {
            if out.len() >= max_len {
                break;
            }
            let pending_token = argmax(&logit_rows[pos]);
            if is_stop(pending_token) {
                out.push(pending_token);
                stopped = true;
                break;
            }
            if pos + 1 >= logit_rows.len() {
                out.push(pending_token);
                break;
            }
            let draft_token = if draft_idx < draft_seq.len() {
                draft_seq[draft_idx]
            } else {
                out.push(pending_token);
                break;
            };
            draft_idx += 1;

            let target_logits_0 = &logit_rows[pos + 1];
            let accepted = draft_token == argmax(target_logits_0);
            let bonus_token = if accepted {
                if pos + 2 < logit_rows.len() {
                    argmax(&logit_rows[pos + 2])
                } else {
                    0
                }
            } else {
                argmax(target_logits_0)
            };

            match mtp_greedy_round(pending_token, draft_token, accepted, bonus_token, is_stop) {
                MtpRoundOutcome::EmitAndStop(tokens) => {
                    let remaining = max_len - out.len();
                    let emit_len = tokens.len().min(remaining);
                    out.extend_from_slice(&tokens[..emit_len]);
                    // FIX 1: stopped only when stop token was actually emitted (not clipped).
                    stopped = emit_len == tokens.len();
                    break;
                }
                MtpRoundOutcome::EmitAndContinue { emit, next_pending } => {
                    let remaining = max_len - out.len();
                    out.extend_from_slice(&emit[..emit.len().min(remaining)]);
                    if out.len() >= max_len {
                        break;
                    }
                    pos = if accepted { pos + 2 } else { pos + 1 };
                    let _ = next_pending;
                }
            }
        }
        (out, stopped)
    }

    #[test]
    fn test_mtp_stopped_stop_token_emitted() {
        // Budget=10: all of [10, 20, EOS] fit → emit_len=3 == tokens.len()=3 → stopped=true.
        let logit_rows = vec![make_logit(10, 5), make_logit(20, 5), make_logit(EOS, 5)];
        let draft_seq = vec![20u32];
        let (tokens, stopped) = simulate_mtp_with_stopped(&logit_rows, &draft_seq, 10);
        assert_eq!(tokens, vec![10, 20, EOS]);
        assert!(stopped, "stop token emitted → stopped must be true");
    }

    #[test]
    fn test_mtp_stopped_stop_token_clipped_at_budget_2() {
        // Budget=2: cap lands before the bonus EOS.
        // EmitAndStop([10, 20, EOS]): emit_len=2 < tokens.len()=3 → stopped=false.
        // Pre-fix (stopped = true): this test goes RED.
        let logit_rows = vec![make_logit(10, 5), make_logit(20, 5), make_logit(EOS, 5)];
        let draft_seq = vec![20u32];
        let (tokens, stopped) = simulate_mtp_with_stopped(&logit_rows, &draft_seq, 2);
        assert_eq!(tokens, vec![10, 20]);
        assert!(
            !stopped,
            "stop token clipped by budget cap → stopped must be false (length cap, not stop)"
        );
    }

    #[test]
    fn test_mtp_stopped_stop_token_clipped_at_budget_1() {
        // Budget=1: only the pending token fits; EOS never reached → stopped=false.
        let logit_rows = vec![make_logit(10, 5), make_logit(20, 5), make_logit(EOS, 5)];
        let draft_seq = vec![20u32];
        let (tokens, stopped) = simulate_mtp_with_stopped(&logit_rows, &draft_seq, 1);
        assert_eq!(tokens, vec![10]);
        assert!(!stopped, "EOS not reached at all → stopped must be false");
    }
}

// ---------------------------------------------------------------------------
// Differential unit tests for `generate_greedy_self_spec` EOS-emission contract.
//
// Strategy: mirror `mtp_greedy_round_tests` — write an independent plain-greedy
// oracle (push token, then check is_stop, bounded by max_new_tokens) and a pure
// simulation of the self-spec round logic. The simulation encodes exactly the
// post-fix decision logic for each termination path WITHOUT re-deriving it from
// the buggy pre-fix code, so it acts as an independent reference.
//
// EOS-faithful contract (matches generate.rs):
//   A:  prefill argmax is EOS → emit [EOS], generated_tokens = 1.
//   R:  rejection: target replacement is stop → emit [pending, stop] before halting.
//   FA: full-accept: next_pending is stop → emit [next_pending] before halting.
//   FB: fallback (no-checkpoint, checkpoint-failure, verify-failure): target's next
//       is stop → emit that stop before halting (budget-clipped).
//
// These tests run on every platform (no cfg gate — no GPU required).
// ---------------------------------------------------------------------------
#[cfg(test)]
mod self_spec_eos_tests {
    const EOS: u32 = 2;

    fn is_stop(id: u32) -> bool {
        id == EOS
    }

    fn argmax(logits: &[f32]) -> u32 {
        logits
            .iter()
            .copied()
            .enumerate()
            .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal))
            .map(|(i, _)| i as u32)
            .unwrap_or(0)
    }

    // -----------------------------------------------------------------------
    // Plain-greedy oracle: push token then check stop, bounded by max_len.
    // Matches generate.rs invariant exactly — stop token is always in output.
    // Independent reference: do NOT derive from self-spec logic.
    // -----------------------------------------------------------------------
    fn plain_greedy_oracle(logit_rows: &[Vec<f32>], max_len: usize) -> Vec<u32> {
        let mut out = Vec::new();
        for row in logit_rows.iter().take(max_len) {
            let token = argmax(row);
            out.push(token);
            if is_stop(token) {
                break;
            }
        }
        out
    }

    // -----------------------------------------------------------------------
    // Self-spec simulation: encodes the fixed per-round decision logic of
    // `generate_greedy_self_spec` as pure token operations, no GPU.
    //
    // Alignment with the real loop and the oracle:
    //   logit_rows[i] = target's logit vector for position i.
    //   argmax(logit_rows[0])   = prefill argmax (first pending).
    //   argmax(logit_rows[i+1]) = target's prediction at pos i+1, used both as
    //                             verify target and as next_pending on full accept.
    //
    // `draft_seq[i]` = the draft proposal at round i.
    //
    // Each round:
    //   - pending_token = logit_rows[pos] argmax
    //   - verify: target agrees if draft_seq[round] == argmax(logit_rows[pos+1])
    //   - on accept: push pending + all agreeing drafts, next_pending = logit_rows[last+1]
    //   - on reject: push pending, target's replacement = argmax(logit_rows[pos+1])
    //   - fallback paths behave like the plain-greedy single-step decode
    //
    // Termination for all paths: push the stop token if budget allows, then break.
    // -----------------------------------------------------------------------
    fn simulate_self_spec(
        logit_rows: &[Vec<f32>],
        // draft_seq[i]: what the draft proposes at round i
        draft_seq: &[u32],
        // simulate_fallback: if true, bypass the normal verify path and use the
        // fallback (single-step decode) path, so we can exercise cases FB.
        simulate_fallback: bool,
        max_len: usize,
    ) -> Vec<u32> {
        assert!(!logit_rows.is_empty(), "need at least one logit row");
        let mut out: Vec<u32> = Vec::new();
        let mut pos = 0usize; // logit_rows index for current pending

        // Case A: prefill argmax is stop → emit it (budget-clipped), return.
        let pending_first = argmax(&logit_rows[pos]);
        if is_stop(pending_first) {
            if max_len > 0 {
                out.push(pending_first);
            }
            return out;
        }

        let mut pending_token = pending_first;
        let mut round = 0usize;

        'round: loop {
            if out.len() >= max_len {
                break;
            }

            if simulate_fallback || pos + 1 >= logit_rows.len() || round >= draft_seq.len() {
                // Fallback path (single-step decode): push pending, check next.
                // Mirrors no-checkpoint / checkpoint-failure / verify-failure sites.
                out.push(pending_token);
                if out.len() >= max_len || pos + 1 >= logit_rows.len() {
                    break;
                }
                let next = argmax(&logit_rows[pos + 1]);
                // Push the terminating stop token before halting (EOS-faithful fix).
                if is_stop(next) {
                    if out.len() < max_len {
                        out.push(next);
                    }
                    break;
                }
                if out.len() >= max_len {
                    break;
                }
                pending_token = next;
                pos += 1;
                round += 1;
                continue 'round;
            }

            let draft = draft_seq[round];
            round += 1;

            // Verify: target agrees with draft if argmax(logit_rows[pos+1]) == draft.
            let target_at_pos1 = argmax(&logit_rows[pos + 1]);
            let accepted = target_at_pos1 == draft;

            if accepted {
                // pending_token is always pushed first.
                out.push(pending_token);
                if is_stop(draft) || out.len() >= max_len {
                    // accept+draft-is-stop: push draft (already correct in original).
                    if !is_stop(draft) {
                        // cap hit — don't push draft
                    } else if out.len() < max_len {
                        out.push(draft);
                    }
                    break;
                }
                out.push(draft);
                if out.len() >= max_len {
                    break;
                }
                // next_pending = target prediction after the last accepted token.
                let next_pending_pos = pos + 2;
                if next_pending_pos >= logit_rows.len() {
                    break;
                }
                let next_pending = argmax(&logit_rows[next_pending_pos]);
                // Full-accept EOS fix: push before halting.
                if is_stop(next_pending) {
                    if out.len() < max_len {
                        out.push(next_pending);
                    }
                    break;
                }
                if out.len() >= max_len {
                    break;
                }
                pending_token = next_pending;
                pos += 2;
            } else {
                // Rejection: push pending, target's replacement is argmax(logit_rows[pos+1]).
                out.push(pending_token);
                let replacement = target_at_pos1;
                // Rejection-EOS fix: push before halting.
                if is_stop(replacement) {
                    if out.len() < max_len {
                        out.push(replacement);
                    }
                    break;
                }
                if out.len() >= max_len {
                    break;
                }
                pending_token = replacement;
                pos += 1;
            }
        }
        out
    }

    fn make_logit(winner: u32) -> Vec<f32> {
        let size = 100usize;
        let mut v = vec![0.0f32; size];
        if (winner as usize) < size {
            v[winner as usize] = 10.0;
        }
        v
    }

    // -----------------------------------------------------------------------
    // Case A: prefill argmax is stop → oracle emits [EOS]; sim must also emit [EOS].
    // Pre-fix: self-spec returned token_ids: vec![], generated_tokens: 0 — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_case_a_prefill_eos() {
        let logit_rows = vec![make_logit(EOS), make_logit(10)];
        let draft_seq = vec![10u32];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![EOS], "oracle sanity: prefill EOS yields [EOS]");

        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, max_len);
        assert_eq!(sim, vec![EOS], "case A: sim must emit [EOS] not []");
        assert_eq!(oracle, sim, "case A: oracle == sim required");
    }

    // -----------------------------------------------------------------------
    // Case A with max_len = 0: no budget → emit nothing (mirrors MTP max_new_tokens=0 guard).
    // -----------------------------------------------------------------------
    #[test]
    fn test_case_a_prefill_eos_zero_budget() {
        let logit_rows = vec![make_logit(EOS), make_logit(10)];
        let draft_seq = vec![10u32];
        let oracle = plain_greedy_oracle(&logit_rows, 0);
        assert_eq!(oracle, Vec::<u32>::new(), "oracle: zero budget → empty");
        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, 0);
        assert_eq!(sim, Vec::<u32>::new(), "case A zero budget: must be empty");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Rejection path: target replacement is stop → oracle/sim both emit [pending, EOS].
    // Pre-fix: self-spec broke WITHOUT pushing next_token — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_rejection_eos() {
        // pos0→10 (pending), pos1→EOS (target; draft proposes 99 = wrong).
        let logit_rows = vec![make_logit(10), make_logit(EOS)];
        let draft_seq = vec![99u32];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, EOS], "rejection-EOS oracle: [10, EOS]");

        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, max_len);
        assert_eq!(sim, vec![10, EOS], "rejection-EOS: sim must match oracle");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Rejection path: budget clips the stop token (max_len = 1).
    // Oracle stops at 1 token; sim must also stop at 1 (do not exceed budget).
    // -----------------------------------------------------------------------
    #[test]
    fn test_rejection_eos_budget_clips_stop() {
        let logit_rows = vec![make_logit(10), make_logit(EOS)];
        let draft_seq = vec![99u32];
        let oracle = plain_greedy_oracle(&logit_rows, 1);
        assert_eq!(oracle, vec![10], "budget-1: oracle emits only pending");
        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, 1);
        assert_eq!(sim, vec![10], "budget-1: sim must not emit stop beyond cap");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Full-accept path: next_pending is stop → oracle/sim both emit [..., EOS].
    // Pre-fix: self-spec broke WITHOUT pushing next_pending — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_full_accept_next_pending_eos() {
        // pos0→10 (pending), pos1→20 (draft=20 accepted), pos2→EOS (next_pending).
        let logit_rows = vec![make_logit(10), make_logit(20), make_logit(EOS)];
        let draft_seq = vec![20u32];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(
            oracle,
            vec![10, 20, EOS],
            "full-accept-EOS oracle: [10, 20, EOS]"
        );

        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, max_len);
        assert_eq!(
            sim,
            vec![10, 20, EOS],
            "full-accept-EOS: sim must match oracle"
        );
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Full-accept path: budget clips EOS (max_len = 2).
    // -----------------------------------------------------------------------
    #[test]
    fn test_full_accept_next_pending_eos_budget_clips() {
        let logit_rows = vec![make_logit(10), make_logit(20), make_logit(EOS)];
        let draft_seq = vec![20u32];
        let oracle = plain_greedy_oracle(&logit_rows, 2);
        assert_eq!(oracle, vec![10, 20], "budget-2: oracle stops before EOS");
        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, 2);
        assert_eq!(sim, vec![10, 20], "budget-2: sim must not exceed cap");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Fallback path (case FB): next token from single-step decode is stop.
    // Pre-fix: all three fallback sites broke WITHOUT pushing next — WRONG.
    // -----------------------------------------------------------------------
    #[test]
    fn test_fallback_path_eos() {
        // pos0→10 (pending), pos1→EOS (single-step decode result).
        let logit_rows = vec![make_logit(10), make_logit(EOS)];
        let draft_seq = vec![]; // unused in fallback mode
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, EOS], "fallback-EOS oracle: [10, EOS]");

        let sim = simulate_self_spec(&logit_rows, &draft_seq, true, max_len);
        assert_eq!(sim, vec![10, EOS], "fallback-EOS: sim must match oracle");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Fallback path: budget clips the stop token (max_len = 1).
    // -----------------------------------------------------------------------
    #[test]
    fn test_fallback_path_eos_budget_clips() {
        let logit_rows = vec![make_logit(10), make_logit(EOS)];
        let draft_seq = vec![];
        let oracle = plain_greedy_oracle(&logit_rows, 1);
        assert_eq!(oracle, vec![10]);
        let sim = simulate_self_spec(&logit_rows, &draft_seq, true, 1);
        assert_eq!(sim, vec![10], "fallback-EOS budget-1: must not exceed cap");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Accept+draft-is-stop: already correct in original — verify it stays correct.
    // Oracle: [pending, EOS].  Sim: [pending, EOS].
    // -----------------------------------------------------------------------
    #[test]
    fn test_accept_draft_is_stop_already_correct() {
        // pos0→10 (pending), pos1→EOS (draft=EOS accepted by target).
        let logit_rows = vec![make_logit(10), make_logit(EOS), make_logit(30)];
        let draft_seq = vec![EOS];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, EOS], "accept+draft-stop oracle: [10, EOS]");

        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, max_len);
        assert_eq!(sim, vec![10, EOS], "accept+draft-stop: already correct");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // No-stop normal sequence: all accepted, no EOS.  Oracle and sim agree.
    // -----------------------------------------------------------------------
    #[test]
    fn test_all_accepted_no_stop() {
        let logit_rows = vec![
            make_logit(10),
            make_logit(20),
            make_logit(30),
            make_logit(40),
        ];
        let draft_seq = vec![20u32, 30, 40];
        let max_len = 4;
        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, max_len);
        assert_eq!(
            oracle, sim,
            "all-accept non-stop: oracle={oracle:?} sim={sim:?}"
        );
    }

    // -----------------------------------------------------------------------
    // Mixed: some accepted, some rejected, EOS at the end via rejection path.
    // -----------------------------------------------------------------------
    #[test]
    fn test_mixed_accept_reject_then_rejection_eos() {
        // target: 10 → 20 → 30 → EOS
        let logit_rows = vec![
            make_logit(10),
            make_logit(20),
            make_logit(30),
            make_logit(EOS),
        ];
        // draft: accept 20 at round0, reject 99 at round1 (target says 30).
        // Then target says EOS at pos2 → reject-EOS path.
        let draft_seq = vec![20u32, 99];
        let max_len = 10;

        let oracle = plain_greedy_oracle(&logit_rows, max_len);
        assert_eq!(oracle, vec![10, 20, 30, EOS]);

        let sim = simulate_self_spec(&logit_rows, &draft_seq, false, max_len);
        assert_eq!(sim, vec![10, 20, 30, EOS], "mixed reject-EOS: got {sim:?}");
        assert_eq!(oracle, sim);
    }

    // -----------------------------------------------------------------------
    // Seeded randomised sweep: oracle vs sim must agree across all EOS positions.
    // Covers all termination paths probabilistically.
    // -----------------------------------------------------------------------
    #[test]
    fn test_randomised_sweep() {
        let mut rng = Lcg::new(0xfeedface_deadbeef);
        let vocab_size = 8usize; // EOS=2
        let trials = 400;

        for trial in 0..trials {
            let seq_len = (rng.next_u64() % 6 + 2) as usize;
            let max_len = 20;
            let fallback = rng.next_u64().is_multiple_of(4); // 25% fallback

            let logit_rows: Vec<Vec<f32>> = (0..=seq_len)
                .map(|_| {
                    let winner = (rng.next_u64() % vocab_size as u64) as usize;
                    let mut row = vec![0.0f32; vocab_size];
                    row[winner] = 10.0;
                    row
                })
                .collect();
            let draft_seq: Vec<u32> = (0..seq_len)
                .map(|_| (rng.next_u64() % vocab_size as u64) as u32)
                .collect();

            let oracle = plain_greedy_oracle(&logit_rows, max_len);
            let sim = simulate_self_spec(&logit_rows, &draft_seq, fallback, max_len);

            assert_eq!(
                oracle,
                sim,
                "trial {trial} (fallback={fallback}): oracle != sim\n  winners={:?}\n  draft={:?}\n  oracle={:?}\n  sim={:?}",
                logit_rows.iter().map(|r| argmax(r)).collect::<Vec<_>>(),
                draft_seq,
                oracle,
                sim,
            );
        }
    }

    // -----------------------------------------------------------------------
    // Seeded randomised sweep with small caps: stresses the budget-clip paths.
    // -----------------------------------------------------------------------
    #[test]
    fn test_randomised_sweep_small_cap() {
        let mut rng = Lcg::new(0xabcd_1234_5678_ef01);
        let vocab_size = 6usize; // EOS=2, frequent stops
        let trials = 400;

        for trial in 0..trials {
            let seq_len = (rng.next_u64() % 6 + 2) as usize;
            let max_len = (rng.next_u64() % 4 + 1) as usize; // 1..=4
            let fallback = rng.next_u64().is_multiple_of(4);

            let logit_rows: Vec<Vec<f32>> = (0..=seq_len)
                .map(|_| {
                    let winner = (rng.next_u64() % vocab_size as u64) as usize;
                    let mut row = vec![0.0f32; vocab_size];
                    row[winner] = 10.0;
                    row
                })
                .collect();
            let draft_seq: Vec<u32> = (0..seq_len)
                .map(|_| (rng.next_u64() % vocab_size as u64) as u32)
                .collect();

            let oracle = plain_greedy_oracle(&logit_rows, max_len);
            let sim = simulate_self_spec(&logit_rows, &draft_seq, fallback, max_len);

            assert!(
                sim.len() <= max_len,
                "trial {trial}: sim exceeded cap {max_len}: {sim:?}"
            );
            assert_eq!(
                oracle,
                sim,
                "trial {trial} (max_len={max_len}, fallback={fallback}): oracle != sim\n  winners={:?}\n  draft={:?}\n  oracle={:?}\n  sim={:?}",
                logit_rows.iter().map(|r| argmax(r)).collect::<Vec<_>>(),
                draft_seq,
                oracle,
                sim,
            );
        }
    }

    /// Minimal deterministic LCG — shared with `mtp_greedy_round_tests`.
    struct Lcg(u64);
    impl Lcg {
        fn new(seed: u64) -> Self {
            Self(seed)
        }
        fn next_u64(&mut self) -> u64 {
            self.0 = self
                .0
                .wrapping_mul(6364136223846793005)
                .wrapping_add(1442695040888963407);
            self.0
        }
    }

    // -----------------------------------------------------------------------
    // FIX 2 & FIX 3: `stopped` semantics for fallback and accepted-draft paths.
    //
    // FIX 2 (five fallback/rejection/full-accept sites in generate_greedy_self_spec):
    //   Pre-fix: `stopped = true` was placed OUTSIDE the budget guard, so a clipped
    //   stop (budget already full) incorrectly set stopped=true. Fix: move
    //   `stopped = true` INSIDE the `generated_ids.len() < max_new_tokens` guard.
    //
    // FIX 3 (accepted-draft stop, inside `for (i, &draft) in draft_tokens...`):
    //   Pre-fix: `break` only exited the inner draft loop, leaving the outer 'round
    //   loop to continue an extra iteration without recording stopped=true. Fix:
    //   `stopped = true; break 'round;` to exit both loops and record the stop.
    //
    // `generate_greedy_self_spec` requires Metal hardware (GPU). These tests drive
    // the identical decision logic via simulate_self_spec_with_stopped.
    //
    // Mutation-sensitivity for FIX 2: move `stopped = true` back outside the guard
    // in simulate_self_spec_with_stopped → test_self_spec_stopped_fallback_eos_clipped
    // goes RED (expected false, got true).
    //
    // Mutation-sensitivity for FIX 3: replace `break 'round` with plain `break` and
    // remove `stopped = true` from simulate_self_spec_with_stopped →
    // test_self_spec_stopped_accepted_draft_stop goes RED (expected true, got false).
    // -----------------------------------------------------------------------
    fn simulate_self_spec_with_stopped(
        logit_rows: &[Vec<f32>],
        draft_seq: &[u32],
        simulate_fallback: bool,
        max_len: usize,
    ) -> (Vec<u32>, bool) {
        assert!(!logit_rows.is_empty(), "need at least one logit row");
        let mut out: Vec<u32> = Vec::new();
        let mut stopped = false;
        let mut pos = 0usize;

        let pending_first = argmax(&logit_rows[pos]);
        if is_stop(pending_first) {
            if max_len > 0 {
                out.push(pending_first);
                stopped = true;
            }
            return (out, stopped);
        }

        let mut pending_token = pending_first;
        let mut round = 0usize;

        'round: loop {
            if out.len() >= max_len {
                break;
            }

            if simulate_fallback || pos + 1 >= logit_rows.len() || round >= draft_seq.len() {
                out.push(pending_token);
                // Mirror production check order: is_stop(next) is evaluated BEFORE the
                // budget guard, exactly as in generate_greedy_self_spec. This makes the
                // simulation mutation-sensitive for FIX 2: when budget is exactly full
                // after pushing pending, the stop token is clipped → stopped stays false.
                if pos + 1 < logit_rows.len() {
                    let next = argmax(&logit_rows[pos + 1]);
                    if is_stop(next) {
                        // FIX 2: stopped=true only when the stop token is actually emitted.
                        // When out.len() >= max_len the stop is clipped → stopped stays false.
                        if out.len() < max_len {
                            out.push(next);
                            stopped = true; // inside budget guard
                        }
                        break;
                    }
                    // Not a stop: continue if budget allows.
                    if out.len() < max_len {
                        pending_token = next;
                        pos += 1;
                        round += 1;
                        continue 'round;
                    }
                }
                break;
            }

            let draft = draft_seq[round];
            round += 1;

            let target_at_pos1 = argmax(&logit_rows[pos + 1]);
            let accepted = target_at_pos1 == draft;

            if accepted {
                out.push(pending_token);
                if is_stop(draft) {
                    if out.len() < max_len {
                        out.push(draft);
                        // FIX 3: record stop and break the outer round loop.
                        stopped = true;
                    }
                    break 'round;
                }
                if out.len() >= max_len {
                    break;
                }
                out.push(draft);
                if out.len() >= max_len {
                    break;
                }
                let next_pending_pos = pos + 2;
                if next_pending_pos >= logit_rows.len() {
                    break;
                }
                let next_pending = argmax(&logit_rows[next_pending_pos]);
                if is_stop(next_pending) {
                    // FIX 2 (full-accept path): stopped only when emitted.
                    if out.len() < max_len {
                        out.push(next_pending);
                        stopped = true;
                    }
                    break;
                }
                if out.len() >= max_len {
                    break;
                }
                pending_token = next_pending;
                pos += 2;
            } else {
                out.push(pending_token);
                let replacement = target_at_pos1;
                if is_stop(replacement) {
                    // FIX 2 (rejection path): stopped only when emitted.
                    if out.len() < max_len {
                        out.push(replacement);
                        stopped = true;
                    }
                    break;
                }
                if out.len() >= max_len {
                    break;
                }
                pending_token = replacement;
                pos += 1;
            }
        }
        (out, stopped)
    }

    // FIX 2: fallback path, budget not full → stop token emitted → stopped=true.
    #[test]
    fn test_self_spec_stopped_fallback_eos_emitted() {
        // Fallback: pending=10, next=EOS. Budget=10. EOS fits → stopped=true.
        let logit_rows = vec![make_logit(10), make_logit(EOS)];
        let (tokens, stopped) = simulate_self_spec_with_stopped(&logit_rows, &[], true, 10);
        assert_eq!(tokens, vec![10, EOS]);
        assert!(
            stopped,
            "EOS emitted in fallback path → stopped must be true"
        );
    }

    // FIX 2: fallback path, budget already full after pushing pending → stop clipped → stopped=false.
    #[test]
    fn test_self_spec_stopped_fallback_eos_clipped() {
        // Fallback: pending=10, next=EOS. Budget=1. After pushing pending, out.len()=1 >= max_len=1.
        // EOS is clipped → stopped=false.
        // Pre-fix (stopped=true outside guard): this test goes RED.
        let logit_rows = vec![make_logit(10), make_logit(EOS)];
        let (tokens, stopped) = simulate_self_spec_with_stopped(&logit_rows, &[], true, 1);
        assert_eq!(tokens, vec![10]);
        assert!(
            !stopped,
            "EOS clipped by budget cap in fallback path → stopped must be false (length cap)"
        );
    }

    // FIX 3: accepted draft is stop token, budget allows → draft emitted → stopped=true.
    #[test]
    fn test_self_spec_stopped_accepted_draft_stop() {
        // logit_rows[0]=10 (pending), logit_rows[1]=EOS (target agrees with draft=EOS).
        // draft accepted, is_stop(draft)=true, budget=10 → EOS pushed → stopped=true.
        // Pre-fix (plain `break` without `stopped=true`): this test goes RED.
        let logit_rows = vec![make_logit(10), make_logit(EOS), make_logit(30)];
        let draft_seq = vec![EOS];
        let (tokens, stopped) = simulate_self_spec_with_stopped(&logit_rows, &draft_seq, false, 10);
        assert_eq!(tokens, vec![10, EOS]);
        assert!(
            stopped,
            "accepted draft is stop token → stopped must be true"
        );
    }

    // FIX 3: accepted draft is stop, but budget is already full after pending → draft clipped → stopped=false.
    #[test]
    fn test_self_spec_stopped_accepted_draft_stop_clipped() {
        // pending=10 pushed (budget=1 full), draft=EOS clipped → stopped=false.
        let logit_rows = vec![make_logit(10), make_logit(EOS), make_logit(30)];
        let draft_seq = vec![EOS];
        let (tokens, stopped) = simulate_self_spec_with_stopped(&logit_rows, &draft_seq, false, 1);
        assert_eq!(tokens, vec![10]);
        assert!(
            !stopped,
            "accepted draft EOS clipped by budget cap → stopped must be false"
        );
    }
}
